operations.new:
function switchTab(tabName) {
  const sameOpenTab =
    sideTabPanel.classList.contains("drawer-open") &&
    ((tabName === "import" && importTab.classList.contains("active")) ||
      (tabName === "settings" && settingsTab.classList.contains("active")) ||
      (tabName === "instructions" && instructionsTab.classList.contains("active")));

  const nextTabName = sameOpenTab ? "" : tabName;
  const showImport = nextTabName === "import";
  const showSettings = nextTabName === "settings";
  const showInstructions = nextTabName === "instructions";
  const drawerOpen = showImport || showSettings || showInstructions;

  sideTabPanel.classList.toggle("drawer-open", drawerOpen);
  importTabBtn.classList.toggle("active", showImport);
  settingsTabBtn.classList.toggle("active", showSettings);
  instructionsTabBtn.classList.toggle("active", showInstructions);

  importTab.classList.toggle("active", showImport);
  settingsTab.classList.toggle("active", showSettings);
  instructionsTab.classList.toggle("active", showInstructions);
}
